import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

const rootDir = process.cwd();
const inputFile = path.join(rootDir, "src", "spelling-engine.jsx");
const outputDir = path.join(rootDir, "worker", "generated");
const outputFile = path.join(outputDir, "spelling-runtime.js");

const source = await readFile(inputFile, "utf8");

const wrapped = [
  "// Generated by scripts/build-spelling-runtime.mjs",
  "export function createSpellingEngineRuntime({ words, wordMeta, storage, tts }) {",
  "  const window = {",
  "    KS2_WORDS_ENRICHED: words,",
  "    KS2_WORD_META: wordMeta,",
  "    KS2_TTS: tts || null,",
  "    crypto: globalThis.crypto,",
  "  };",
  "  const localStorage = storage;",
  "",
  source.trim(),
  "",
  "  return window.SpellingEngine;",
  "}",
  "",
].join("\n");

await mkdir(outputDir, { recursive: true });
await writeFile(outputFile, wrapped, "utf8");
